// ═══════════════════════════════════════════════════════════════
// NODO: Prepare_Manager_Executive_Report_v4
// DESC: Dashboard Executive con terminologia tecnica e logica SiteBoS
// ═══════════════════════════════════════════════════════════════

const input = $input.first().json;

// 1. RECUPERO DATI CORE
const doc = input.final_certification_doc || {};
const owner = input.owner_data || {};
const bObj = input.Final_Blueprint || {};

// --- LOGICA DI CATEGORIZZAZIONE FERREA ---
const name = (doc.blueprint_info.name || "").toUpperCase();
const sku = (doc.sop_id || "").toUpperCase();

let typeLabel = "DOCUMENTO";
let typeIcon = "📄";

if (name.includes("[SOP]") || sku.startsWith("SOP_")) {
    typeLabel = "[SOP] PROCEDURA OPERATIVA";
    typeIcon = "📋";
} else if (name.includes("[SER]") || sku.startsWith("SER_") || sku.startsWith("SVC_")) {
    typeLabel = "[SER] SERVIZIO";
    typeIcon = "🛠️";
} else if (name.includes("[PRO]") || sku.startsWith("PRO_") || sku.startsWith("PRD_")) {
    typeLabel = "[PRO] PRODOTTO";
    typeIcon = "📦";
}

// 2. ANALISI METRICHE KPI
const totalSteps = doc.total_steps_executed;
const aiSteps = doc.audit_trail.filter(s => s.method.includes("AI")).length;
const healthScore = Math.round((aiSteps / totalSteps) * 100);
const healthBar = "🟩".repeat(Math.floor(healthScore/10)) + "⬜".repeat(10 - Math.floor(healthScore/10));

const actualTime = doc.timing.duration_minutes;
const estimatedTime = bObj.summary?.estimated_total_time_minutes || 0;
const timePerformance = actualTime <= estimatedTime ? "🟢 OTTIMALE" : "🔴 OVER-TIME";

// 3. RICOSTRUZIONE LOG EVENTI
let auditTrailHtml = "";
doc.audit_trail.forEach((step) => {
    const time = new Date(step.timestamp).toLocaleTimeString('it-IT', { hour: '2-digit', minute: '2-digit' });
    const methodIcon = step.method.includes("AI") ? "🤖" : "✍️";
    auditTrailHtml += ` ├ <code>${time}</code> ${methodIcon} ${step.step_name}\n`;
});

// 4. COSTRUZIONE EXECUTIVE DASHBOARD (HTML)
const reportMessage = `
🏛️ <b>SITEBOS - EXECUTIVE AUDIT REPORT</b>
━━━━━━━━━━━━━━━━━━━━
🏷️ <b>CATEGORIA:</b> <code>${typeLabel}</code>
📝 <b>ATTIVITÀ:</b> <b>${doc.blueprint_info.name}</b>
🆔 <b>SESSIONE:</b> <code>${doc.execution_id}</code>

🎯 <b>OBIETTIVO STRATEGICO</b>
<i>"${doc.blueprint_info.description}"</i>

📊 <b>PERFORMANCE OPERATIVA</b>
────────────────────
⏱️ <b>Tempo Totale:</b> <code>${actualTime} min</code> (Target: ${estimatedTime}m)
📈 <b>Efficienza:</b> <code>${timePerformance}</code>
✅ <b>Integrità:</b> <code>${healthScore}% AI-Validated</code>
   ${healthBar}

📝 <b>LOG DI ESECUZIONE</b>
────────────────────
${auditTrailHtml}
 └ 🏁 <i>Sessione chiusa e certificata.</i>

━━━━━━━━━━━━━━━━━━━━
🔐 <b>INTEGRITÀ:</b> <code>VERIFIED</code>
🛡️ <b>ARCHIVIAZIONE:</b> <code>VAULT SECURE SITEBOS</code>`;

// 5. OUTPUT PAYLOAD
return [{
    json: {
        ...input,
        manager_report: {
            bot_token: owner.bot_key,
            chat_id: owner.chat_id,
            text: reportMessage,
            parse_mode: "HTML"
        }
    }
}];

const fItem = $input.first().json;
const bObj = fItem.Final_Blueprint || fItem.Blueprint;
const oInfo = fItem.owner_data;
const body = fItem.body;

const sopId = body.sop_id;
const execId = body.ei;
const stepId = body.step_id;
const vat = oInfo.vat_number;
const tracking_report_id = `${vat}_${sopId}_${execId}`;

let allSteps = [];
bObj.stages.forEach((stg, sIndex) => {
    stg.steps.forEach(stp => {
        allSteps.push({ ...stp, stageNum: sIndex + 1 });
    });
});

const currentIdx = allSteps.findIndex(s => s.step_id === stepId);
const currentStep = allSteps[currentIdx];
const nextStep = allSteps[currentIdx + 1];

const manualCallback = nextStep ? `ge_si=${sopId}&ei=${execId}&sti=${nextStep.step_id}` : `ge_close_${tracking_report_id}`;
const webAppUrl = `https://simonaiit.github.io/SiteBoS-MiniApp/certificator.html?sop_id=${sopId}&step_id=${stepId}&message_id=${body.message_id}&evidence_type=${body.evidence_type}&ei=${execId}&vat=${vat}&chat_id=${body.chat_id}&SBS=true`;

const msgText = `⚠️ <b>AI TEMPORANEAMENTE OFFLINE</b>\nNessun credito scalato. Riprova o procedi manualmente.\n━━━━━━━━━━━━━━━━━━━━\n<b>[STEP ${currentIdx + 1} di ${allSteps.length}]</b>\n⚙️ STEP: <b>${currentStep.step_name}</b>\n\n📖 ISTRUZIONI:\n${currentStep.instructions}\n━━━━━━━━━━━━━━━━━━━━\n🆔 Sessione: <code>${execId}</code>`;

return [{
  json: {
    ...fItem,
    telegramApiPayload: {
      method: "editMessageText",
      chat_id: oInfo.chat_id,
      message_id: body.message_id,
      text: msgText,
      parse_mode: "HTML",
      reply_markup: {
        inline_keyboard: [[
            { text: "✍️ Autocertifica", callback_data: manualCallback },
            { text: "🔄 Riprova AI", web_app: { url: webAppUrl } }
        ]]
      }
    }
  }
}];

const fItem = $input.first().json;
const bObj = fItem.Final_Blueprint || fItem.Blueprint;
const oInfo = fItem.owner_data;
const body = fItem.body;
const aiLog = fItem.Evicence_Rational_Log;

const sopId = body.sop_id;
const execId = body.ei;
const stepId = body.step_id;
const vat = oInfo.vat_number;
const tracking_report_id = `${vat}_${sopId}_${execId}`;

let allSteps = [];
bObj.stages.forEach((stg, sIndex) => {
    stg.steps.forEach(stp => {
        allSteps.push({ ...stp, stageName: stg.stage_name, stageDesc: stg.description, stageNum: sIndex + 1 });
    });
});

const currentIdx = allSteps.findIndex(s => s.step_id === stepId);
const currentStep = allSteps[currentIdx];
const nextStep = allSteps[currentIdx + 1];

// Tracking Report: Fallimento AI
let tracking_report = {
    report_id: tracking_report_id,
    exec_id: execId,
    timestamp: new Date().toISOString(),
    event_type: "AI_REJECTION",
    status: "LOCKED",
    details: aiLog.rationale
};

// Callback Manuale (passa al prossimo o chiude)
const manualCallback = nextStep ? `ge_si=${sopId}&ei=${execId}&sti=${nextStep.step_id}` : `ge_close_${tracking_report_id}`;
const webAppUrl = `https://simonaiit.github.io/SiteBoS-MiniApp/certificator.html?sop_id=${sopId}&step_id=${stepId}&message_id=${body.message_id}&evidence_type=${body.evidence_type}&ei=${execId}&vat=${vat}&chat_id=${body.chat_id}&SBS=true`;

const msgText = `🛑 <b>EVIDENZA RESPINTA</b>\n❌ <b>MOTIVO:</b> <i>${aiLog.rationale}</i>\n💡 <b>AZIONE:</b> ${aiLog.strategic_insight}\n━━━━━━━━━━━━━━━━━━━━\n<b>[STEP ${currentIdx + 1} di ${allSteps.length}]</b>\n⚙️ STEP: <b>${currentStep.step_name}</b>\n\n📖 ISTRUZIONI:\n${currentStep.instructions}\n\n✅ VALIDAZIONE:\n• <i>${currentStep.quality_check.check_description}</i>\n━━━━━━━━━━━━━━━━━━━━\n🆔 Sessione: <code>${execId}</code>`;

return [{
  json: {
    ...fItem,
    tracking_report: tracking_report,
    telegramApiPayload: {
      method: "editMessageText",
      chat_id: oInfo.chat_id,
      message_id: body.message_id,
      text: msgText,
      parse_mode: "HTML",
      reply_markup: {
        inline_keyboard: [[
            { text: "✍️ Autocertifica", callback_data: manualCallback },
            { text: "📸 Riprova AI", web_app: { url: webAppUrl } }
        ]]
      }
    }
  }
}];

const fItem = $input.first().json;

// 1. RECUPERO BASI DATI (Allineato a v4.4 e Final Document)
const bObj = fItem.Final_Blueprint || fItem.Blueprint;
const oInfo = fItem.owner_data;
const body = fItem.body; // Dati dal Webhook Mini App (sop_id, ei, step_id)
const aiLog = fItem.Evicence_Rational_Log;
const history = fItem.messages || fItem.Cert_Step || []; // Storico per Audit Trail

const sopId = body.sop_id;
const execId = body.ei;
const vat = oInfo.vat_number;
const tracking_report_id = `${vat}_${sopId}_${execId}`;
const operator = fItem.user; 

// 2. COSTRUZIONE SEQUENZA STEP COMPLETA (Flattening)
let allSteps = [];
bObj.stages.forEach((stg, sIndex) => {
    stg.steps.forEach(stp => {
        allSteps.push({ 
            ...stp, 
            stageName: stg.stage_name, 
            stageDesc: stg.description,
            stageNum: sIndex + 1
        });
    });
});

// 3. INDIVIDUAZIONE POSIZIONI
const completedIdx = allSteps.findIndex(s => s.step_id === body.step_id);
const isFinalStep = (completedIdx === allSteps.length - 1); // <--- IL TUO SEMAFORO

const currentStepToDisplay = allSteps[completedIdx + 1]; // Il prossimo da mostrare (se esiste)
const nextStepAfterThat = allSteps[completedIdx + 2];    // Serve per il callback manuale del prossimo step

// 4. GENERAZIONE TRACKING REPORT (Certificazione dello step appena fatto)
let tracking_report = {
    report_id: tracking_report_id,
    exec_id: execId,
    sop_id: sopId,
    vat: vat,
    timestamp: new Date().toISOString(),
    event_type: "STEP_COMPLETED",
    status: isFinalStep ? "COMPLETED" : "IN_PROGRESS",
    completed_step: {
        id: body.step_id,
        name: allSteps[completedIdx].step_name,
        method: "AI_CERTIFIED - " + (aiLog.rationale || "Nessun dettaglio fornito"),
        operator_chat_id: body.chat_id
    }
};

const L = (oInfo.lenguage || 'it').toLowerCase().includes('en') ? 'en' : 'it';
function clean(t) { return t ? String(t).replace(/<(?!b|i|u|code|a|pre|\/b|\/i|\/u|\/code|\/a|\/pre)[^>]+>/gi, '') : ''; }

// =============================================================================
// CASO A: NON È L'ULTIMO STEP (Mostra Rich UI v4.4 dello step successivo)
// =============================================================================
if (!isFinalStep) {
    const t = {
        it: { procedure: "📂 PROCEDURA:", stage: "📍 FASE ATTUALE:", stepInfo: "⚙️ DETTAGLI STEP:", instr: "📖 ISTRUZIONI OPERATIVE:", check: "✅ CRITERI DI VALIDAZIONE:", btn_man: "✍️ Autocertifica", btn_ai: "Certificazione AI" },
        en: { procedure: "📂 PROCEDURE:", stage: "📍 CURRENT STAGE:", stepInfo: "⚙️ STEP DETAILS:", instr: "📖 OPERATIONAL INSTRUCTIONS:", check: "✅ VALIDATION CRITERIA:", btn_man: "✍️ Self-Certify", btn_ai: "AI Certification" }
    }[L];

    const evType = (currentStepToDisplay.quality_check?.evidence_type || "VISION").toUpperCase();
    const evIcon = evType === "VISION" ? "📸" : (evType === "FILE" ? "📄" : "📝");

    // Callback manuale: se c'è uno step dopo quello che stiamo visualizzando vai a quello, altrimenti ge_close
    const manualCallback = nextStepAfterThat 
        ? `ge_si=${sopId}&ei=${execId}&sti=${nextStepAfterThat.step_id}` 
        : `ge_close_${tracking_report_id}`;

    const webAppUrl = `https://simonaiit.github.io/SiteBoS-MiniApp/certificator.html?sop_id=${sopId}&step_id=${currentStepToDisplay.step_id}&message_id=${body.message_id}&evidence_type=${evType}&ei=${execId}&SBS=true`;

    const msgText = `
✅ <b>STEP PRECEDENTE VALIDATO CON AI</b>
━━━━━━━━━━━━━━━━━━━━
<b>[STEP ${completedIdx + 2} di ${allSteps.length}]</b>
━━━━━━━━━━━━━━━━━━━━
${t.procedure}
<b>${bObj.blueprint_name}</b>

${t.stage}
<b>${currentStepToDisplay.stageNum}. ${currentStepToDisplay.stageName}</b>
<i>${currentStepToDisplay.stageDesc}</i>

━━━━━━━━━━━━━━━━━━━━
${t.stepInfo}
<b>${currentStepToDisplay.step_name}</b>
⏱️ Tempo: <code>${currentStepToDisplay.estimated_time_minutes || 'N/D'} min</code>

${t.instr}
${currentStepToDisplay.instructions}

${t.check}
• <i>${currentStepToDisplay.quality_check.check_description}</i>
• <b>Target:</b> ${currentStepToDisplay.quality_check.acceptance_criteria}

━━━━━━━━━━━━━━━━━━━━
👤 Operatore: <b>${operator.first_name}</b>
🆔 Sessione: <code>${execId}</code>`;

    return [{
      json: {
        ...fItem,
        is_final_step: false,
        tracking_report: tracking_report,
        telegramApiPayload: {
          method: "editMessageText",
          chat_id: oInfo.chat_id,
          message_id: body.message_id,
          text: msgText,
          parse_mode: "HTML",
          reply_markup: {
            inline_keyboard: [[
                { text: t.btn_man, callback_data: manualCallback },
                { text: `${evIcon} ${t.btn_ai}`, web_app: { url: webAppUrl } }
            ]]
          }
        }
      }
    }];

} 
// =============================================================================
// CASO B: ERA L'ULTIMO STEP (Genera Documento Finale e Chiudi)
// =============================================================================
else {
    const startData = history.length > 0 ? (history[0].kwargs || history[0]) : {};
    const startAt = startData.timestamp || new Date().toISOString(); 
    const closedAt = new Date().toISOString();

    let execution_log = [];
    history.forEach((msg) => {
        const k = msg.kwargs || msg;
        if (k.event_type === "STEP_COMPLETED") {
            execution_log.push({ step_id: k.completed_step.id, step_name: k.completed_step.name, method: k.completed_step.method, timestamp: k.timestamp });
        }
    });
    // Inseriamo l'ultimo step (quello attuale)
    execution_log.push({
        step_id: body.step_id,
        step_name: allSteps[completedIdx].step_name,
        method: "AI_VISION_CERTIFIED",
        timestamp: closedAt
    });

    const final_certification_doc = {
        document_type: "CERTIFICATION_RECORD",
        version: "1.0",
        certification_id: tracking_report_id,
        execution_id: execId,
        sop_id: sopId,
        company_info: { vat: vat, operator_chat_id: oInfo.chat_id },
        blueprint_info: { name: bObj.blueprint_name, description: bObj.blueprint_description },
        status: "COMPLETED",
        timing: {
            started_at: startAt,
            closed_at: closedAt,
            duration_minutes: Math.round((new Date(closedAt) - new Date(startAt)) / 60000)
        },
        total_steps_executed: execution_log.length,
        audit_trail: execution_log
    };

    const tF = {
        it: { title: "📜 <b>CERTIFICATO EMESSO</b>", body: `Procedura: <b>"${bObj.blueprint_name}"</b>`, start: "🏁 Inizio:", end: "✅ Fine:", btn_man: "✍️ Autocertifica" },
        en: { title: "📜 <b>CERTIFICATE ISSUED</b>", body: `Procedure: <b>"${bObj.blueprint_name}"</b>`, start: "🏁 Started:", end: "✅ Completed:", btn_man: "✍️ Self-Certify" }
    }[L];

    const fmtTime = (iso) => new Date(iso).toLocaleTimeString(L === 'it' ? 'it-IT' : 'en-US', { hour: '2-digit', minute: '2-digit' });

    const finalMsgText = `
${tF.title}
━━━━━━━━━━━━━━━━━━━━
${tF.body}

🆔 Sessione: <code>${execId}</code>
${tF.start} <code>${fmtTime(startAt)}</code>
${tF.end} <code>${fmtTime(closedAt)}</code>

📊 Totale Step: <b>${execution_log.length}</b>
━━━━━━━━━━━━━━━━━━━━
🛡️ <i>Documento archiviato e validato con AI.</i>
👉 Clicca sotto per finalizzare l'invio.`;

    return [{
      json: {
        ...fItem,
        is_final_step: true, 
        tracking_report: tracking_report
          }
    }];
}

const fItem = $input.first().json;

// 1. RECUPERO DATI CORE
const bObj = fItem.Final_Blueprint || fItem.Blueprint || {};
const oInfo = fItem.owner_data || {};
const body = fItem.body || {};
const history = fItem.messages || []; 
const currentTrack = fItem.tracking_report || {};

const sopId = body.sop_id;
const execId = body.ei;
const vat = oInfo.vat_number;
const tracking_report_id = `${vat}_${sopId}_${execId}`;

// 2. ESTRAZIONE ORARIO INIZIO (Dalla history)
const openEvent = history.find(m => m.kwargs && m.kwargs.event_type === "INSTANCE_OPEN");
const startAt = openEvent ? openEvent.kwargs.timestamp : new Date().toISOString();
const closedAt = new Date().toISOString();

// 3. COSTRUZIONE AUDIT TRAIL (Merging History + Current Step)
let execution_log = [];

history.forEach((msg) => {
    const k = msg.kwargs || {};
    if (k.event_type === "STEP_COMPLETED") {
        execution_log.push({
            step_id: k.completed_step.id,
            step_name: k.completed_step.name,
            method: k.completed_step.method,
            timestamp: k.timestamp
        });
    }
});

if (currentTrack.completed_step) {
    execution_log.push({
        step_id: currentTrack.completed_step.id,
        step_name: currentTrack.completed_step.name,
        method: currentTrack.completed_step.method,
        timestamp: currentTrack.timestamp
    });
}

// 4. GENERAZIONE DOCUMENTO FINALE PER MONGODB
const final_certification_doc = {
    document_type: "CERTIFICATION_RECORD",
    version: "1.0",
    certification_id: tracking_report_id,
    execution_id: execId,
    sop_id: sopId,
    company_info: {
        vat: vat,
        operator_chat_id: body.chat_id
    },
    blueprint_info: {
        name: bObj.blueprint_name,
        description: bObj.blueprint_description
    },
    status: "COMPLETED",
    timing: {
        started_at: startAt,
        closed_at: closedAt,
        duration_minutes: Math.round((new Date(closedAt) - new Date(startAt)) / 60000)
    },
    total_steps_executed: execution_log.length,
    audit_trail: execution_log
};

// 5. PREPARAZIONE MESSAGGIO TELEGRAM (CON IL TUO PULSANTE ORIGINALE)
const L = (oInfo.lenguage || 'it').toLowerCase().includes('en') ? 'en' : 'it';
const t = {
    it: {
        title: "📜 <b>CERTIFICATO EMESSO</b>",
        body: `Procedura: <b>"${bObj.blueprint_name}"</b>`,
        start: "🏁 Inizio:",
        end: "✅ Fine:",
        btn: "⬅️ Torna alla Procedura"
    },
    en: {
        title: "📜 <b>CERTIFICATE ISSUED</b>",
        body: `Procedure: <b>"${bObj.blueprint_name}"</b>`,
        start: "🏁 Started:",
        end: "✅ Completed:",
        btn: "⬅️ Back to Procedure"
    }
}[L];

const fmtTime = (iso) => new Date(iso).toLocaleTimeString(L === 'it' ? 'it-IT' : 'en-US', { hour: '2-digit', minute: '2-digit' });

const msgText = `
${t.title}
━━━━━━━━━━━━━━━━━━━━
${t.body}

🆔 Sessione: <code>${execId}</code>
${t.start} <code>${fmtTime(startAt)}</code>
${t.end} <code>${fmtTime(closedAt)}</code>

📊 Totale Step: <b>${execution_log.length}</b>
━━━━━━━━━━━━━━━━━━━━
🛡️ <i>Documento archiviato nel Registro SiteBoS.</i>`;

return [{
  json: {
    ...fItem,
    final_certification_doc: final_certification_doc,
    is_final_step: true,
    telegramApiPayload: {
      method: "editMessageText",
      chat_id: oInfo.chat_id,
      message_id: body.message_id,
      text: msgText,
      parse_mode: "HTML",
      reply_markup: {
        inline_keyboard: [[
            { text: t.btn, callback_data: `get_active_sop_${sopId}` }
        ]]
      }
    }
  }
}];

